import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch15: CareerQuestion[] = [
  { id: "ota-2403", stem: "An OTA is treating a client with an unstable distal radioulnar joint (DRUJ). Which motion should be limited?", options: ["Wrist flexion", "Forceful forearm pronation and supination to protect the unstable DRUJ until healing is complete", "Finger flexion", "Shoulder motion"], correctIndex: 1, rationale: "DRUJ instability: limit forceful pronation/supination (stresses the DRUJ). Splint forearm in neutral rotation, gentle AROM within tolerance, and modify activities to avoid rotational torque through the forearm.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2404", stem: "A client with a spinal cord injury at T4 is at risk for orthostatic hypotension when transitioning from supine to sitting. What should the OTA do?", options: ["Sit up quickly", "Gradually elevate the head of the bed, use an abdominal binder and compression stockings, and monitor blood pressure during position changes", "Skip sitting activities", "Only treat in supine"], correctIndex: 1, rationale: "T4 SCI orthostatic hypotension: gradual elevation (raise head progressively), abdominal binder (improves venous return), compression stockings, monitor BP, increase fluid/salt intake, and tilt table progression.", difficulty: 2, category: "Patient Safety", topic: "Neurological Rehab" },
  { id: "ota-2405", stem: "An OTA is treating a child with hemiplegic cerebral palsy. Which bimanual training approach promotes use of the affected hand?", options: ["Only use the unaffected hand", "Hand-Arm Bimanual Intensive Training (HABIT) — intensive structured bimanual activities that require the affected hand to participate as an assist", "Constraint of the affected hand", "Only passive ROM"], correctIndex: 1, rationale: "HABIT: intensive bimanual training where activities are structured so the affected hand must participate (stabilize, hold, support). Promotes coordinated bilateral use in functional tasks. Evidence supports improved bimanual function in hemiplegic CP.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2406", stem: "A client with Wernicke's aphasia has fluent but meaningless speech. How should the OTA communicate?", options: ["Speak louder and faster", "Use visual demonstrations, gestures, written cues, and short simple instructions — the client has impaired auditory comprehension despite fluent verbal output", "Only verbal instructions", "Avoid communication entirely"], correctIndex: 1, rationale: "Wernicke's aphasia: fluent speech but poor comprehension. OTA should use visual demonstrations, gestures, written cues (if reading preserved), short simple phrases, yes/no questions, and environmental context to support understanding.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2407", stem: "An OTA is treating a client with a healing metacarpal shaft fracture. At 4 weeks, what treatment is appropriate?", options: ["No treatment until 8 weeks", "Protected AROM of the MCP joint with buddy taping, gentle edema management, and functional activities within pain tolerance", "Aggressive passive stretching", "Heavy grip strengthening"], correctIndex: 1, rationale: "Metacarpal shaft fracture at 4 weeks: protected AROM of MCPs (composite flexion/extension), buddy taping for support, edema management, scar massage if applicable, and functional activities within pain limits. Resistive exercises at 6-8 weeks.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2408", stem: "A client with early-onset dementia (age 58) is struggling with work performance. What OT intervention is appropriate?", options: ["Only home modifications", "Workplace accommodations, compensatory cognitive strategies, transition planning, caregiver education, and maintaining valued roles and activities as long as possible", "Immediate retirement recommendation", "Only medication management"], correctIndex: 1, rationale: "Early-onset dementia work: workplace accommodations (checklists, reminders, reduced complexity), compensatory cognitive strategies, transition planning, role preservation, meaningful activity engagement, caregiver education, and advance planning.", difficulty: 3, category: "Geriatric Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2409", stem: "An OTA is fabricating an ulnar gutter splint for a 5th metacarpal fracture. What position is maintained?", options: ["Full MCP extension", "MCP at 70° flexion, PIP/DIP free for motion, and wrist in 20-30° extension to maintain functional position during healing", "Full finger flexion", "Wrist in full flexion"], correctIndex: 1, rationale: "Ulnar gutter splint for 5th MC fracture: wrist 20-30° extension, MCP 70° flexion (protects collateral ligaments), PIP/DIP free for motion. Includes 4th and 5th rays. Buddy tape 4th and 5th fingers during activities.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2410", stem: "A client with chronic schizophrenia demonstrates poor hygiene and grooming. Which model guides OT intervention?", options: ["Only behavioral modification", "The Model of Human Occupation (MOHO) — addressing habituation (establishing grooming routines), volition (motivation), and performance capacity in the context of the client's environment", "Only medication management", "No OT intervention for hygiene"], correctIndex: 1, rationale: "MOHO for schizophrenia hygiene: address habituation (establish daily routine), volition (connect grooming to valued roles/interests), performance capacity (cognitive/motor skills for grooming), and environment (organize supplies, visual cues).", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2411", stem: "An OTA is providing driving rehabilitation for a client with a left CVA. What cognitive skill is essential for safe driving?", options: ["Only vision", "Attention, divided attention (monitoring multiple inputs simultaneously), processing speed, judgment, and problem-solving for rapid decision-making in traffic", "Only motor skills", "Only memory"], correctIndex: 1, rationale: "Driving cognitive requirements: sustained attention, divided attention (mirrors, road, gauges), selective attention (filtering distractions), processing speed, judgment, problem-solving, and executive function for split-second decisions.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2412", stem: "A client with a severe hand laceration has both flexor and extensor tendon injuries. What splinting approach accommodates both repairs?", options: ["No splinting", "Modified position that balances protection of both flexor and extensor repairs — typically wrist slight flexion, MCPs flexion, IPs neutral, following the surgeon's specific protocol", "Standard resting hand splint", "Only flexor protection"], correctIndex: 1, rationale: "Combined flexor/extensor repair: splinting must balance protection of both structures (opposing positions). Position per surgeon protocol — typically a modified dorsal blocking splint with limited extension. Motion protocols carefully coordinated.", difficulty: 5, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2413", stem: "An OTA is treating a client with a total knee arthroplasty who has a continuous passive motion (CPM) machine. What does the OTA assess?", options: ["Only ROM settings", "Proper limb positioning in the device, skin integrity under straps, ROM settings matching physician orders, and functional carryover of gained ROM to ADLs", "Only electrical safety", "Nothing related to CPM"], correctIndex: 1, rationale: "CPM assessment by OTA: limb positioning, skin integrity, ROM settings per orders, comfort during use, compliance, and functional carryover — ensuring CPM-gained ROM translates to improved ADL performance (transfers, dressing, bathing).", difficulty: 2, category: "Clinical Case Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2414", stem: "A client with a suprascapular nerve injury has difficulty with shoulder external rotation and abduction. Which muscles are affected?", options: ["Deltoid and pectoralis", "Supraspinatus (abduction initiation) and infraspinatus (external rotation) — both innervated by the suprascapular nerve", "Biceps and triceps", "Trapezius and rhomboids"], correctIndex: 1, rationale: "Suprascapular nerve: innervates supraspinatus (shoulder abduction 0-15°) and infraspinatus (external rotation). Injury causes difficulty initiating abduction and weakness in ER. Common in overhead athletes and fractures.", difficulty: 4, category: "Anatomy & Physiology", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2415", stem: "An OTA is providing intervention for a client with a gambling addiction. What OT approach is appropriate?", options: ["Only financial counseling", "Identify triggers and high-risk situations, develop alternative leisure activities, time management skills, stress management, and rebuilding healthy habits and routines", "No OT role in gambling", "Only group therapy"], correctIndex: 1, rationale: "Gambling addiction OT: identify triggers/high-risk situations, develop alternative leisure/occupations, time management (structure unstructured time), stress management, healthy coping skills, routine rebuilding, and financial management referral.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2416", stem: "A client with bilateral carpal tunnel syndrome is a dental hygienist. What ergonomic modifications does the OTA recommend?", options: ["Change careers only", "Neutral wrist positioning, instrument modification (larger handles), micro-breaks, stretching program, and workstation adjustment to reduce repetitive wrist flexion/extension", "Only wrist splints", "No modifications possible"], correctIndex: 1, rationale: "Dental hygienist CTS ergonomics: neutral wrist position, larger instrument handles, reduced pinch force, micro-breaks every 20-30 minutes, stretching program, loupes/proper positioning to reduce neck/shoulder strain, and alternating tasks.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2417", stem: "An OTA is treating a client with a healing ulnar nerve transposition. What motion should be protected?", options: ["Shoulder motion", "Elbow flexion beyond the surgeon's prescribed limit — excessive flexion can stretch the transposed ulnar nerve in the early healing phase", "Wrist motion", "Finger motion"], correctIndex: 1, rationale: "Ulnar nerve transposition precautions: limit elbow flexion per surgeon (typically <90° for 3-4 weeks), avoid valgus stress, gentle AROM within limits, and progressive flexion increase as healing permits. Monitor for Tinel's sign improvement.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2418", stem: "A client with severe bilateral hand osteoarthritis has difficulty managing medication bottles. What is the simplest solution?", options: ["Stop medications", "Request non-child-resistant caps from the pharmacy and use a weekly pill organizer filled by a pharmacist or caregiver", "Stronger grip exercises only", "Only liquid medications"], correctIndex: 1, rationale: "Medication management with hand OA: non-child-resistant caps (request from pharmacy), weekly pill organizer (pre-filled), automatic pill dispensers, medication management apps for reminders, and pharmacy blister packaging.", difficulty: 1, category: "Assistive Devices", topic: "Geriatric OT" },
  { id: "ota-2419", stem: "An OTA is treating a client with Charcot-Marie-Tooth disease. What is the typical pattern of weakness?", options: ["Proximal weakness only", "Distal-to-proximal weakness starting in the feet and hands — stork leg appearance and claw hand deformity from intrinsic muscle atrophy", "Only upper extremity weakness", "Facial weakness primarily"], correctIndex: 1, rationale: "Charcot-Marie-Tooth: hereditary motor sensory neuropathy. Distal-to-proximal weakness: feet/ankles first (foot drop, stork legs), then hands (claw hand, intrinsic atrophy). Sensory loss, pes cavus. OT: adaptive equipment, hand function, and orthoses.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2420", stem: "A client with a hip fracture is on non-weight-bearing status. Which transfer technique is appropriate?", options: ["Stand-pivot transfer", "Sliding board transfer or stand-pivot on the unaffected leg only with appropriate assistive device and arms for support", "Squat transfer", "Dependent lift only"], correctIndex: 1, rationale: "NWB hip fracture transfers: sliding board (if unable to stand), or stand-pivot on unaffected leg with walker support. Affected leg must not bear weight. OTA trains technique, ensures safety, and provides appropriate assistive devices.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2421", stem: "An OTA is treating a client with a shoulder labral repair (SLAP lesion). What movement is restricted postoperatively?", options: ["All shoulder motion", "Active external rotation, overhead activities, and biceps loading — the labral repair involves the biceps anchor and requires protection from specific forces", "Only internal rotation", "No restrictions"], correctIndex: 1, rationale: "SLAP repair precautions: protect biceps anchor (avoid active ER, overhead activities, biceps loading). Sling 4-6 weeks, PROM per surgeon, AROM at 6 weeks, strengthening at 12 weeks. OTA addresses modified ADLs during recovery.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2422", stem: "A client with autism spectrum disorder in a vocational program has difficulty with unexpected schedule changes. What support helps?", options: ["More surprises for flexibility", "Visual schedules with advance warning of changes, social stories about flexibility, a backup plan routine, and a calm-down strategy for when changes occur", "No accommodations", "Only verbal reminders"], correctIndex: 1, rationale: "ASD schedule changes: advance warning (visual timer), visual schedule showing change, social stories about flexibility, designated backup routine, calm-down strategy, and gradually introducing minor changes to build tolerance.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2423", stem: "An OTA is performing a functional capacity evaluation (FCE) for a client returning to work. What does this assessment measure?", options: ["Only grip strength", "The client's safe and reliable ability to perform work-related physical tasks including lifting, carrying, sitting, standing, reaching, and fine motor activities", "Only pain level", "Only endurance"], correctIndex: 1, rationale: "FCE: comprehensive evaluation of work capacity — lifting/carrying (floor to waist, waist to overhead), pushing/pulling, sitting/standing tolerance, walking, reaching, fine motor, and positional tolerance. Assesses safe, reliable, and sustainable work ability.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2424", stem: "A client with a healing Achilles tendon repair has been cleared for partial weight-bearing. What bathing adaptation is necessary?", options: ["Normal shower standing", "Shower chair to avoid full weight-bearing through the affected leg, non-slip mat, and long-handled sponge for lower extremity hygiene below the cast/boot", "Bath only", "Sponge bath indefinitely"], correctIndex: 1, rationale: "Achilles repair PWB bathing: shower chair (reduces weight-bearing demands), non-slip mat, waterproof cast/boot cover if applicable, long-handled sponge, and grab bars for transfer safety.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2425", stem: "An OTA is treating a client with thoracic outlet syndrome. Which posture contributes to symptom exacerbation?", options: ["Upright posture", "Forward head posture with rounded shoulders and protracted scapulae — this narrows the thoracic outlet and compresses neurovascular structures", "Prone positioning", "Side-lying position"], correctIndex: 1, rationale: "Thoracic outlet syndrome postural factors: forward head, rounded shoulders, protracted scapulae narrow the thoracic outlet. Treatment: postural correction, scapular stabilization, cervical stretching, ergonomic modifications, and nerve gliding exercises.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2426", stem: "A client with chronic heart failure has a left ventricular assist device (LVAD). What precaution is essential during OT?", options: ["No special precautions", "Protect the driveline exit site from trauma, avoid activities that may disconnect the power source, and monitor for signs of device malfunction", "Avoid all movement", "Only upper body exercises"], correctIndex: 1, rationale: "LVAD precautions: protect driveline (no pulling, bending, or trauma to exit site), maintain power source connections, waterproof driveline during bathing, monitor for alarms, know emergency procedures, and activity within cardiac guidelines.", difficulty: 3, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2427", stem: "An OTA is treating a child with a brachial plexus birth injury who is now 2 years old. What is the OT focus?", options: ["Only surgery", "Functional play activities that encourage use of the affected arm, strengthening within play, stretching to prevent contractures, and adaptive strategies for bilateral tasks", "No treatment at this age", "Only passive stretching"], correctIndex: 1, rationale: "Brachial plexus injury at age 2: functional play to encourage affected arm use, bilateral activities, stretching during play to prevent contractures, strengthening, and adaptive strategies. Developmentally appropriate play-based intervention.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2428", stem: "A client with a recent coronary artery bypass graft (CABG) has sternal precautions. Which ADL technique violates these precautions?", options: ["Eating with one hand", "Pushing up from a chair using both arms — this creates bilateral shoulder force that stresses the healing sternum", "Brushing teeth", "Using a reacher"], correctIndex: 1, rationale: "Sternal precautions: avoid pushing up from surfaces with both arms (bilateral shoulder force stresses sternum). Instead: sit at edge of chair, lean forward, and use legs to stand. Also avoid pulling, lifting >5-10 lbs, and bilateral overhead reaching.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2429", stem: "An OTA is using motor learning principles in treatment. What practice schedule promotes long-term retention?", options: ["Massed practice only", "Distributed practice with random task ordering — spacing practice sessions and varying task order improves long-term retention over massed blocked practice", "Blocked practice only", "No practice schedule matters"], correctIndex: 1, rationale: "Motor learning: distributed practice (rest between sessions) promotes better retention than massed practice. Random practice (varying task order) improves transfer and retention despite worse performance during practice (contextual interference effect).", difficulty: 3, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2430", stem: "A client with psoriatic arthritis has DIP joint involvement. How does this differ from rheumatoid arthritis?", options: ["No difference", "Psoriatic arthritis preferentially affects DIP joints and has asymmetric presentation, while RA typically spares DIPs and presents symmetrically in MCPs and PIPs", "RA also affects DIPs", "Psoriatic arthritis is bilateral"], correctIndex: 1, rationale: "Psoriatic vs RA joint patterns: psoriatic = DIP involvement, asymmetric, dactylitis (sausage digits), enthesitis, skin/nail changes. RA = MCP/PIP (spares DIPs), symmetric, subcutaneous nodules, morning stiffness >1 hour.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2431", stem: "An OTA is treating a client with a traumatic brain injury who demonstrates confabulation. What does this mean?", options: ["Intentional lying", "Filling in memory gaps with fabricated information without awareness of doing so — the client genuinely believes the false memories are real", "Improved memory", "Visual hallucinations"], correctIndex: 1, rationale: "Confabulation: fabricating memories to fill gaps without awareness. Not intentional lying. Common in TBI, Korsakoff syndrome. Avoid correcting confrontationally. Redirect gently, provide factual information, and use memory aids.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2432", stem: "A client with newly diagnosed rheumatoid arthritis is anxious about the disease progression. What psychosocial support does the OTA provide?", options: ["Only joint exercises", "Education about the disease process, self-management strategies, stress management techniques, community resource connection, and support group referral", "Only medication education", "No psychosocial support in OT"], correctIndex: 1, rationale: "RA psychosocial support: disease education, self-management empowerment, stress management (stress can trigger flares), coping strategies, community resources (Arthritis Foundation), support group referral, and addressing role/identity changes.", difficulty: 1, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2433", stem: "An OTA is treating a client with a healing digital nerve repair. When is sensory re-education initiated?", options: ["Immediately after surgery", "When protective sensation returns (positive response to 30g Semmes-Weinstein monofilament) — typically 6-8 weeks after nerve repair as regeneration progresses distally", "After full sensation returns", "Never for nerve repairs"], correctIndex: 1, rationale: "Sensory re-education timing: begin early phase when protective sensation returns (30g monofilament response). Late phase when moving touch detected. Exercises: texture discrimination, object identification, graphesthesia, and functional sensory tasks.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2434", stem: "A client with end-stage renal disease on hemodialysis is fatigued and deconditioned. What energy conservation strategy is MOST important?", options: ["Do everything on dialysis days", "Schedule demanding activities on non-dialysis days, pace activities throughout the day, prioritize essential tasks, and delegate non-essential activities", "Push through fatigue", "Only rest all day"], correctIndex: 1, rationale: "ESRD on dialysis energy conservation: schedule activities on non-dialysis days (fatigue peaks post-dialysis), prioritize tasks, pace activities, delegate, use adaptive equipment, plan rest periods, and maintain activity diary.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2435", stem: "An OTA is leading an anger management group for adolescents. Which activity addresses emotional regulation?", options: ["Competitive sports only", "Role-playing scenarios, identifying triggers, practicing deep breathing and progressive relaxation, and developing a personal anger management toolbox", "Only lecture on anger", "No OT role in anger management"], correctIndex: 1, rationale: "Adolescent anger management OT: identify triggers (anger thermometer), role-play alternative responses, deep breathing/PMR practice, coping strategy toolbox, assertiveness training, creative expression, and practice in real-life situations.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2436", stem: "A client with a swan neck deformity secondary to rheumatoid arthritis is having difficulty grasping objects. What splint helps?", options: ["MCP extension splint", "Silver ring splint or figure-of-eight splint that blocks PIP hyperextension while allowing flexion for functional grasp", "Full hand resting splint", "Thumb spica splint"], correctIndex: 1, rationale: "Swan neck deformity splinting: silver ring splint or figure-of-eight splint blocks PIP hyperextension (allows flexion for grasp). Cosmetically acceptable and functional. Enables improved pinch and grasp by preventing PIP snapping into hyperextension.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2437", stem: "An OTA is evaluating a client's cognitive status using the Allen Cognitive Level Screen (ACLS). What functional level does a score of 4.0 indicate?", options: ["Independent functioning", "Goal-directed actions — the client can perform familiar activities with setup and supervision but has difficulty with new learning and problem-solving", "Comatose level", "Completely independent"], correctIndex: 1, rationale: "Allen ACL 4.0 (Goal-Directed Actions): can perform familiar routine tasks with setup and cues. Difficulty with new learning, problem-solving, and anticipating consequences. Requires structured environment and routine. 24-hour supervision for safety.", difficulty: 3, category: "Clinical Scenarios", topic: "Cognitive Rehab" },
  { id: "ota-2438", stem: "A client with a new prosthetic leg is learning to navigate ramps. What technique does the OTA teach?", options: ["Run up the ramp", "Ascending: lean slightly forward with shorter steps; descending: lean slightly backward with controlled steps; always use handrails when available", "Only use elevators", "No special technique needed"], correctIndex: 1, rationale: "Prosthetic leg ramp navigation: ascending — lean forward slightly, shorter steps, handrail use. Descending — lean slightly back, controlled step length, handrail use. Practice on different inclines. Key for community mobility independence.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2439", stem: "An OTA is providing intervention for a client with hoarding disorder. Which psychological factor contributes to hoarding behavior?", options: ["Only laziness", "Emotional attachment to objects, fear of waste, information processing deficits, indecisiveness, and distorted beliefs about the necessity and usefulness of possessions", "Only financial concerns", "Only lack of storage"], correctIndex: 1, rationale: "Hoarding psychological factors: emotional attachment to objects, fear of waste/making wrong decisions, cognitive processing deficits (categorization, attention), indecisiveness, distorted beliefs about possession necessity, and avoidance of negative emotion.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2440", stem: "A client with a recent amputation has phantom limb sensation (not pain). Is this normal?", options: ["Never normal", "Yes — phantom limb sensation (awareness of the missing limb) is extremely common and normal after amputation; it differs from phantom limb pain", "Always requires treatment", "Indicates poor healing"], correctIndex: 1, rationale: "Phantom limb sensation: extremely common (up to 90% of amputees). Normal neurological phenomenon — awareness of the missing limb's position, shape, or movement. Different from phantom limb pain. Usually decreases over time.", difficulty: 1, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2441", stem: "An OTA is treating a client with a volar plate injury at the PIP joint. What complication may develop if not properly managed?", options: ["No complications", "PIP hyperextension deformity (swan neck) due to volar plate incompetence allowing the PIP to hyperextend", "Wrist drop", "Thumb opposition loss"], correctIndex: 1, rationale: "Volar plate injury complication: PIP hyperextension (swan neck deformity) if volar plate heals too loosely. Extension blocking splint prevents hyperextension during healing. Dorsal blocking splint at 30° PIP flexion for 3-4 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2442", stem: "A client with an intellectual disability is learning to use a microwave for meal preparation. Which teaching method is MOST effective?", options: ["Written manual", "Forward chaining with visual cue cards — teach the first step until mastered, then add subsequent steps progressively while using picture-based instructions", "Verbal lecture", "Only demonstration without practice"], correctIndex: 1, rationale: "Microwave training for ID: forward chaining (master each step before adding next), visual cue cards (pictures of each step), consistent routine, errorless learning, systematic prompting, and fade prompts as independence increases.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2443", stem: "An OTA is evaluating a child's motor planning abilities. Which activity assesses praxis?", options: ["Passive ROM assessment", "Asking the child to imitate novel body positions or perform unfamiliar motor sequences that require planning, sequencing, and executing new movements", "Reflex testing", "Muscle strength testing"], correctIndex: 1, rationale: "Praxis assessment: imitation of novel postures (not previously learned), perform unfamiliar motor sequences, constructional tasks, and use unfamiliar tools. Tests ideation, motor planning, and execution — distinguishing from simple motor skill deficits.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2444", stem: "A client with obstructive sleep apnea is using CPAP and reports difficulty tolerating the mask. What OT intervention may help?", options: ["Remove CPAP", "Systematic desensitization to the mask, mask fitting assistance, bedtime routine modification, and relaxation techniques to improve CPAP tolerance and compliance", "Only medication for sleep", "No OT role"], correctIndex: 1, rationale: "CPAP tolerance OT: systematic desensitization (wear mask during daytime activities first), mask fitting/adjustment, relaxation techniques at bedtime, sleep hygiene education, and addressing psychological barriers to CPAP compliance.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2445", stem: "An OTA is treating a client with a replanted thumb. At 6 weeks post-surgery, what is the treatment priority?", options: ["Maximum resistance exercises", "Gentle AROM within surgeon guidelines, scar management, edema control, and sensory re-education as nerve regeneration begins", "Full activity without restrictions", "No treatment needed"], correctIndex: 1, rationale: "Thumb replantation at 6 weeks: gentle AROM within surgeon limits, scar management (massage, silicone), edema control, desensitization, sensory re-education (as regeneration occurs), and progressive functional use. No resistive exercise yet.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2446", stem: "A client with a pelvic fracture is on non-weight-bearing status. What is the OTA's role?", options: ["Only wait for fracture to heal", "Modified transfer training, adapted ADLs using NWB techniques, upper body strengthening, and energy conservation for wheelchair-level activities", "Ambulation training", "No OT role"], correctIndex: 1, rationale: "Pelvic fracture NWB: OT provides modified transfers (sliding board, stand-pivot on unaffected side), adapted ADLs (bathing, dressing, toileting from wheelchair level), UE strengthening, and wheelchair management training.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2447", stem: "An OTA is treating a client with a progressive neurological condition who is experiencing anticipatory grief. What is the appropriate OT response?", options: ["Avoid discussing feelings", "Acknowledge the client's feelings, facilitate meaningful occupation engagement, support legacy building, connect to support resources, and maintain hope while being realistic about progression", "Only refer to psychology", "Focus only on physical function"], correctIndex: 1, rationale: "Anticipatory grief in progressive conditions: acknowledge feelings, facilitate meaningful occupations, legacy activities (memory books, recordings), connect to peer support, maintain hope while being realistic, and support client's autonomy in decision-making.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2448", stem: "A client with a proximal row carpectomy is undergoing hand therapy. What is the expected functional outcome?", options: ["No wrist motion", "Reduced but functional wrist ROM (about 50% of normal) with pain relief and maintained grip strength for functional hand use", "Normal ROM restoration", "Complete loss of function"], correctIndex: 1, rationale: "Proximal row carpectomy outcomes: reduced wrist ROM (~50% of normal), good pain relief, maintained or improved grip strength, and functional hand use for ADLs. Motion arc typically sufficient for most daily activities.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2449", stem: "An OTA is providing intervention for a client with borderline personality disorder. What therapeutic boundary is essential?", options: ["Flexible boundaries", "Clear, consistent, and firm therapeutic boundaries communicated at the outset of treatment and maintained throughout the therapeutic relationship", "No boundaries needed", "Only physical boundaries"], correctIndex: 1, rationale: "BPD therapeutic boundaries: clear, consistent, communicated early, maintained firmly but compassionately, documented, and coordinated with the treatment team. Avoid splitting, special relationships, and boundary blurring. Dialectical approach: validate + set limits.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2450", stem: "A client with bilateral total knee replacements is 5 days post-surgery. What ADL priority does the OTA address?", options: ["Cooking", "Toilet transfers, lower body dressing with adaptive equipment, and basic mobility for safe discharge home", "Gardening", "Community mobility"], correctIndex: 1, rationale: "Bilateral TKR day 5 OT priorities: toilet transfers (raised seat, grab bars), lower body dressing (reacher, sock aid, long shoe horn), basic transfers (bed, chair, commode), and bathing (tub bench). Focus on safe discharge home.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2451", stem: "An OTA is treating a client with a scaphoid fracture in a thumb spica cast. What exercises should be performed during immobilization?", options: ["No exercises during casting", "Active ROM of the uninvolved fingers (full composite fist), shoulder and elbow ROM, and edema prevention exercises of the free digits", "Only wrist exercises inside the cast", "Resistance exercises of the immobilized hand"], correctIndex: 1, rationale: "Scaphoid fracture during immobilization: AROM of free fingers (composite fist, finger extension), shoulder/elbow ROM to prevent stiffness, edema management (elevation, finger pumping), and general conditioning of uninvolved extremity.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2452", stem: "A client with a traumatic brain injury has impaired topographical orientation. What does this deficit involve?", options: ["Difficulty naming objects", "Difficulty navigating familiar routes, finding locations, and creating mental maps of the environment", "Difficulty reading", "Difficulty with calculations"], correctIndex: 1, rationale: "Topographical disorientation: inability to navigate familiar environments, find locations, or create/use mental maps. Caused by right parietal or hippocampal damage. Compensate with maps, written directions, landmarks, and GPS technology.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2453", stem: "An OTA is providing intervention for a child with selective mutism. What OT approach helps?", options: ["Force the child to speak", "Create a comfortable, low-pressure therapeutic environment, use nonverbal communication initially, gradually increase verbal demands, and embed communication in play activities", "Only refer to SLP", "Punish silence"], correctIndex: 1, rationale: "Selective mutism OT: low-pressure environment, nonverbal communication first, gradual exposure to verbal demands, play-based activities (embed communication naturally), consistent warm approach, and collaborate with SLP and psychology.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2454", stem: "A client with severe rheumatoid arthritis uses a power wheelchair. What ergonomic consideration is essential for hand protection?", options: ["Standard joystick", "Joystick with built-up handle to reduce grip force, proportional control for fine adjustments, and positioning to minimize wrist stress during driving", "No modifications needed", "Manual wheelchair instead"], correctIndex: 1, rationale: "RA power wheelchair modifications: built-up joystick (reduces grip force), proportional control, joystick positioned for neutral wrist, arm support during driving, and alternative controls if hand function deteriorates further.", difficulty: 3, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2455", stem: "An OTA is treating a client with Crohn's disease who has had bowel surgery. What precaution is relevant to OT?", options: ["No precautions", "Monitor for fatigue, nutritional status, and abdominal discomfort during activities; avoid heavy lifting per surgical restrictions; and accommodate bathroom urgency needs", "Only dietary restrictions", "Avoid all exercise"], correctIndex: 1, rationale: "Crohn's post-surgery OT: monitor fatigue and nutritional status, abdominal precautions per surgeon, accommodate bathroom access needs, energy conservation, activity pacing, and address psychosocial impact of bowel disease.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2456", stem: "A client with a traumatic below-elbow amputation is learning to tie shoes with a prosthesis. What training technique is used?", options: ["Only Velcro shoes", "Break the task into components, practice each component (prosthesis stabilizes one lace while the intact hand manipulates), and use repetitive practice for automaticity", "Standard shoe-tying only", "No training possible"], correctIndex: 1, rationale: "Prosthetic shoe tying: task analysis (break into steps), prosthesis as stabilizer (holds one lace/shoe), intact hand manipulates. Practice components then whole task. Alternative: elastic laces, Velcro closures, or one-handed techniques.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2457", stem: "An OTA is treating a client with ankylosing spondylitis. What postural exercise is essential?", options: ["Thoracic flexion exercises", "Extension exercises for the thoracic spine, chest expansion activities, and maintaining upright posture to prevent progressive kyphotic deformity", "Only rest", "Forward bending stretches"], correctIndex: 1, rationale: "Ankylosing spondylitis: progressive thoracic kyphosis if not managed. Extension exercises (thoracic/cervical), chest expansion (deep breathing, stretching), upright posture maintenance, sleeping flat (minimize pillows), and aquatic therapy.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2458", stem: "A client with visual-perceptual deficits has difficulty with figure-ground perception. What functional impact does this have?", options: ["No functional impact", "Difficulty finding objects in cluttered drawers, locating items on busy shelves, reading on patterned backgrounds, and distinguishing foreground from background in visual scenes", "Only affects reading", "Only affects driving"], correctIndex: 1, rationale: "Figure-ground deficit: difficulty separating foreground from background. Functional impacts: finding objects in drawers/closets, locating items on shelves, reading on patterned backgrounds, and navigating busy visual environments.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2459", stem: "An OTA is assessing an elderly client for home safety. Which room feature poses the greatest fall risk in the bedroom?", options: ["Window curtains", "Throw rugs on smooth flooring surfaces — these can slide and cause tripping, especially for clients with shuffling gait or decreased proprioception", "Wall art", "Table lamps"], correctIndex: 1, rationale: "Bedroom fall risks: throw rugs on smooth floors (sliding/tripping), poor lighting, cluttered pathways to bathroom, bed height too high/low, electrical cords across paths, and lack of nightlight for nighttime navigation.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2460", stem: "A client with a healing extensor pollicis longus (EPL) tendon repair needs which splint?", options: ["Volar wrist splint", "Thumb extension splint or hand-based thumb spica that maintains thumb IP and MCP extension while protecting the repaired EPL tendon", "Standard resting hand splint", "No splint needed"], correctIndex: 1, rationale: "EPL repair splinting: thumb IP extension, hand-based or forearm-based splint maintaining thumb retropulsion and IP extension. Avoid resistive thumb flexion. Controlled motion protocol per surgeon. EPL is vulnerable to rupture at Lister's tubercle.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2461", stem: "An OTA is treating a client with chronic pain who has been told 'the pain is all in your head.' What is the OTA's appropriate response?", options: ["Agree with the statement", "Validate the client's pain experience, explain that all pain is processed in the brain and is real regardless of its origin, and focus on functional improvement strategies", "Suggest the client is exaggerating", "Only refer to psychology"], correctIndex: 1, rationale: "Chronic pain validation: all pain is real and processed in the brain. Validate the experience, provide pain neuroscience education, focus on function (not cure), build self-efficacy, and use occupation-based approaches for meaningful engagement.", difficulty: 2, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2462", stem: "A client with a recent liver transplant is in acute rehabilitation. What unique complication should the OTA monitor?", options: ["Only wound healing", "Signs of organ rejection (jaundice, fever, abdominal pain, dark urine) and medication side effects (tremor from immunosuppressants, increased infection risk)", "Only balance", "Only appetite"], correctIndex: 1, rationale: "Liver transplant monitoring: rejection signs (jaundice, fever, abdominal pain, dark urine, fatigue), immunosuppressant side effects (tremor, nephrotoxicity, infection risk), surgical wound healing, and nutritional status.", difficulty: 3, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2463", stem: "An OTA is treating a child with hemiplegia who demonstrates associated reactions. What does this mean?", options: ["Normal movement", "Involuntary movement or increased tone in the hemiplegic limb that occurs with effort or activity in other body parts — indicating excessive overflow from movement effort", "Voluntary movement", "Relaxed muscle tone"], correctIndex: 1, rationale: "Associated reactions: involuntary increase in tone/movement in the hemiplegic limb when effort is exerted elsewhere (coughing, yawning, walking, lifting with sound hand). Indicates abnormal neural overflow. Manage with positioning and tone reduction techniques.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2464", stem: "A client with severe carpal tunnel syndrome has thenar muscle atrophy. What functional deficit results?", options: ["Wrist extension weakness", "Loss of thumb opposition and weakened pinch strength — inability to perform precise pinch activities such as picking up coins, buttoning, and writing", "Only numbness", "Loss of grip entirely"], correctIndex: 1, rationale: "CTS thenar atrophy: loss of opponens pollicis and abductor pollicis brevis function. Results in inability to oppose thumb for precision pinch. Affects fine motor tasks (buttons, coins, keys, writing). May need surgical referral and post-operative OT.", difficulty: 3, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2465", stem: "An OTA is providing intervention for a client with major depressive disorder who has psychomotor retardation. What activity level is appropriate?", options: ["High-intensity exercise", "Low-demand, structured activities that can be completed successfully, gradually increasing demands as psychomotor function and motivation improve", "No activity at all", "Only competitive sports"], correctIndex: 1, rationale: "MDD with psychomotor retardation: start with low-demand activities (simple grooming, gentle movement), success-oriented experiences, gradual increase in demands, structured routine, and graded activity to build momentum and self-efficacy.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2466", stem: "A client with a wrist fusion (arthrodesis) has which functional limitation?", options: ["No limitations", "Loss of wrist flexion and extension but maintained forearm rotation — difficulty with tasks requiring wrist positioning, requiring compensatory techniques for ADLs", "Loss of all hand function", "Loss of finger motion"], correctIndex: 1, rationale: "Wrist arthrodesis: eliminates wrist flexion/extension (fused in 10-20° extension). Forearm rotation preserved. Compensate with shoulder/elbow positioning for tasks requiring wrist motion. Most ADLs achievable with adaptation.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2467", stem: "An OTA is evaluating a client's ability to manage an emergency situation. What cognitive skills are assessed?", options: ["Only reading ability", "Problem-solving, judgment, decision-making speed, ability to sequence emergency procedures, and capacity to communicate the emergency to responders", "Only memory", "Only attention"], correctIndex: 1, rationale: "Emergency management cognitive assessment: problem identification, judgment (severity assessment), decision-making speed, sequencing emergency procedures (call 911, provide info), communication ability, and ability to follow dispatcher instructions.", difficulty: 2, category: "Rehabilitation Planning", topic: "Cognitive Rehab" },
  { id: "ota-2468", stem: "A client with spastic hemiplegia has increased flexor tone in the wrist and fingers. Which technique inhibits this spasticity?", options: ["Quick stretch of flexors", "Weight-bearing through an extended wrist with fingers open on a flat surface — sustained stretch and joint approximation inhibit spastic flexor tone", "Rapid passive motion", "Cold application to flexors"], correctIndex: 1, rationale: "Spasticity inhibition: weight-bearing through extended wrist/fingers (sustained stretch + joint approximation), slow prolonged stretch, positioning in extension, rhythmic rotation, and functional activities in extended positions to normalize tone.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2469", stem: "An OTA is treating a client who has had a laryngectomy. What communication method does the OTA support?", options: ["Normal speech", "Alternative communication methods including electrolarynx, esophageal speech, tracheoesophageal puncture speech, or communication boards while coordinating with SLP", "Only writing", "No communication is possible"], correctIndex: 1, rationale: "Laryngectomy communication: electrolarynx (vibration held against neck), esophageal speech (learned belching), tracheoesophageal puncture (TEP with voice prosthesis), and communication boards/apps. OTA supports functional use and ADL adaptation.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2470", stem: "A client with severe tremors is having difficulty eating soup. Which bowl adaptation is MOST helpful?", options: ["Regular bowl", "Weighted bowl with a non-slip base and high sides, used with a weighted spoon with a deep bowl, to prevent spilling during tremor-affected feeding", "Shallow plate instead", "Only use a straw"], correctIndex: 1, rationale: "Tremor feeding soup: weighted bowl with non-slip base (reduces movement), high-sided bowl or plate guard (prevents spilling), weighted deep-bowled spoon, swivel spoon (stays level), and non-slip mat under the bowl.", difficulty: 1, category: "Assistive Devices", topic: "ADL Training" },
  { id: "ota-2471", stem: "An OTA is providing therapy for a client with chronic fatigue syndrome/myalgic encephalomyelitis (CFS/ME). What is the pacing strategy?", options: ["Activity until exhaustion", "Activity within the energy envelope — doing 80% of maximum capacity, alternating activity and rest, and stopping BEFORE fatigue to prevent post-exertional malaise", "No activity is safe", "Graded exercise therapy at maximum intensity"], correctIndex: 1, rationale: "CFS/ME pacing: stay within the 'energy envelope' (80% of capacity), activity-rest cycling, stop before fatigue, avoid boom-bust pattern, maintain consistent daily activity level, and prevent post-exertional malaise (symptom flare from overexertion).", difficulty: 3, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2472", stem: "A client with a traumatic amputation of the ring and small fingers has which functional impact?", options: ["No functional impact", "Reduced grip strength (loss of ulnar-sided power grip), difficulty with cylindrical grasp, and need to adapt pinch patterns", "Complete loss of hand function", "Only cosmetic concern"], correctIndex: 1, rationale: "Ring/small finger amputation: loss of ulnar-sided power grip (approximately 40% grip strength loss), difficulty with cylindrical grasp, compensatory grip patterns needed, and maintained precision pinch with index-middle-thumb.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Hand Therapy" },
  { id: "ota-2473", stem: "An OTA is treating a client with early Parkinson's disease. What home exercise program is evidence-based?", options: ["Only passive stretching", "Large-amplitude movements (LSVT BIG-inspired), balance exercises, dual-task training, and regular aerobic exercise to slow functional decline", "Only relaxation exercises", "No home exercise is beneficial"], correctIndex: 1, rationale: "Early PD home exercise: LSVT BIG-inspired large-amplitude movements, balance training, dual-task practice, aerobic exercise (30 minutes most days), flexibility, and functional task practice. Exercise is neuroprotective in PD.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2474", stem: "A client with severe anxiety is learning relaxation techniques. Which approach is BEST for the initial session?", options: ["Full body PMR", "Diaphragmatic breathing — the simplest relaxation technique to learn and can be practiced anywhere without special equipment or position", "Yoga poses", "Guided imagery with complex scenes"], correctIndex: 1, rationale: "Initial relaxation training: diaphragmatic breathing (simplest, most portable, no equipment needed). Progress to PMR, guided imagery, mindfulness, and body scan. Breathing can be used anywhere as a first-line coping strategy.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2475", stem: "An OTA is treating a client with a healing zone II flexor tendon repair at 5 weeks. What exercise can now be introduced?", options: ["Heavy resistance grip", "Place-and-hold exercises — actively extending the fingers then having the client hold the passively positioned flexed position using their own muscle effort", "Aggressive passive extension", "Full active ROM without protection"], correctIndex: 1, rationale: "Zone II flexor tendon repair at 5 weeks: place-and-hold exercises (therapist passively flexes, client maintains position with own muscle effort). This produces less tendon force than full active flexion while promoting tendon gliding and strength.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2476", stem: "A client with a vestibular migraine has dizziness triggered by visual stimulation. What environmental modification helps?", options: ["More visual stimulation", "Reduce visual complexity in the environment, avoid flickering lights, use solid-colored backgrounds, and limit screen time to reduce visually triggered vestibular symptoms", "Only sunglasses", "Only medication"], correctIndex: 1, rationale: "Vestibular migraine visual triggers: reduce visual complexity, avoid flickering/fluorescent lights, solid backgrounds (not busy patterns), limit screen time, anti-glare screen filters, and gradual exposure to visually complex environments.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2477", stem: "An OTA is evaluating a child's in-hand manipulation skills. Which task assesses translation?", options: ["Cutting with scissors", "Moving a coin from the fingertips into the palm (finger-to-palm translation) or from the palm to the fingertips (palm-to-finger translation) using one hand", "Stacking blocks", "Threading beads"], correctIndex: 1, rationale: "In-hand manipulation translation: finger-to-palm (moving object from fingertips to palm) and palm-to-finger (moving from palm to fingertips). Tests: moving coins into palm, retrieving a coin from palm for insertion. Develops 3-6 years.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2478", stem: "A client with a traumatic brain injury at Rancho Level VII is appropriate for which level of community reintegration?", options: ["No community activities", "Supervised community outings with structure — the client is automatic-appropriate in structured settings but has decreased judgment in unstructured community situations", "Full independent community access", "Only hospital-based activities"], correctIndex: 1, rationale: "Rancho Level VII (Automatic-Appropriate): carries out daily routine automatically in structured settings. Lacks insight into deficits, decreased judgment in unfamiliar situations, needs supervision for community safety and decision-making support.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2479", stem: "An OTA is treating a client with chronic CRPS who has developed a contracture. What time-limited approach is used?", options: ["Forceful manipulation", "Serial casting or static progressive splinting to gradually increase range — low-load prolonged stress applied for extended periods to remodel contracted tissue", "No treatment for contractures in CRPS", "Only dynamic splinting"], correctIndex: 1, rationale: "CRPS contracture: serial casting or static progressive splinting (LLPS principle), gentle sustained stretch, stress loading, functional activities, and careful monitoring for pain exacerbation. Avoid forceful manipulation which worsens CRPS.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2480", stem: "A client with dementia in a long-term care facility wanders at night. What non-pharmacological intervention is appropriate?", options: ["Physical restraints", "Consistent bedtime routine, adequate daytime activity, nightlight illumination, secured environment (door alarms, enclosed garden), and addressing underlying needs (hunger, toileting, anxiety)", "Lock the client in their room", "Only sedating medication"], correctIndex: 1, rationale: "Dementia wandering management: consistent routine, adequate daytime activity (reduce restlessness), nightlights, secured environment (door alarms, not locks), address underlying needs, familiar objects in room, and calming evening routine.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2481", stem: "An OTA is providing therapy to a client with a healing olecranon fracture fixation. What motion is initially protected?", options: ["Shoulder motion", "Avoid resistive elbow extension against gravity and impact loading — the olecranon is the triceps insertion and extension force stresses the fixation site", "Forearm rotation", "Wrist motion"], correctIndex: 1, rationale: "Olecranon fracture fixation: protect from resistive/forceful elbow extension (stresses triceps insertion and fixation). Begin AROM per surgeon, avoid weight-bearing through the elbow, and progressive strengthening at 6-8 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2482", stem: "A client with multiple chemical sensitivity (MCS) has difficulty tolerating therapy environments. What accommodation is essential?", options: ["Use more fragranced products", "Provide a fragrance-free treatment environment, use unscented products, ensure adequate ventilation, and avoid latex and strong chemical cleaners", "No accommodations possible", "Treat in standard environment"], correctIndex: 1, rationale: "MCS accommodations: fragrance-free environment (no perfumes, scented products), adequate ventilation, unscented cleaning products, latex-free supplies, scheduled times when fewer people present, and outdoor therapy when possible.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2483", stem: "An OTA is evaluating a client's performance using the Kohlman Evaluation of Living Skills (KELS). What does this assessment measure?", options: ["Only physical abilities", "Functional living skills across self-care, safety/health, money management, transportation, telephone use, and work/leisure needed for community living", "Only cognitive function", "Only social skills"], correctIndex: 1, rationale: "KELS: assesses functional living skills for community placement decisions. Domains: self-care, safety/health, money management, transportation, telephone use, and work/leisure. Administered in 30-45 minutes. Used in psychiatric and rehabilitation settings.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2484", stem: "A client with spinal stenosis has pain with prolonged standing and walking. Which position provides symptom relief?", options: ["Lumbar extension", "Lumbar flexion — sitting, bending forward, or leaning on a shopping cart opens the spinal canal and reduces neural compression symptoms", "Prone position", "Supine with legs flat"], correctIndex: 1, rationale: "Spinal stenosis: lumbar flexion opens the spinal canal (reduces compression). Symptoms worse with extension/standing. Relief with sitting, forward leaning, shopping cart posture. OT modifies ADLs to incorporate flexion-biased positions.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2485", stem: "An OTA is providing intervention for a client with trichotillomania. Which habit reversal technique is used?", options: ["Ignore the behavior", "Awareness training (identifying triggers and urge), competing response practice (making a fist, crossing arms when urge arises), and social support", "Only medication", "Shave the client's head"], correctIndex: 1, rationale: "Trichotillomania habit reversal: awareness training (identify triggers, early signs of urge), competing response (incompatible action when urge arises — fist clenching, crossing arms), social support, relaxation training, and stimulus control.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2486", stem: "A client with a cerebral palsy has an intrathecal baclofen pump. What should the OTA be aware of?", options: ["No special considerations", "Know the pump location (usually abdomen), avoid pressure over the pump site, recognize withdrawal symptoms (increased spasticity, fever, seizures), and adapt activities around the device", "Ignore the pump during therapy", "Remove the pump during activities"], correctIndex: 1, rationale: "Intrathecal baclofen pump: located in abdomen, avoid pressure/impact over site, recognize withdrawal signs (rebound spasticity, fever, sweating, seizures — medical emergency), and adapt positioning/activities around the device.", difficulty: 3, category: "Patient Safety", topic: "Neurological Rehab" },
  { id: "ota-2487", stem: "An OTA is treating a client with hand tendinitis. What is the difference between tendinitis and tendinosis?", options: ["They are identical", "Tendinitis is acute inflammation of the tendon; tendinosis is chronic tendon degeneration without inflammation — treatment differs significantly between the two conditions", "Only tendinitis exists", "Tendinosis is always painful, tendinitis is not"], correctIndex: 1, rationale: "Tendinitis: acute inflammatory response (responds to anti-inflammatory treatment). Tendinosis: chronic degenerative changes without inflammation (responds to eccentric exercise, blood flow promotion). Important distinction for treatment approach selection.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2488", stem: "A client with a right hemisphere stroke has anosognosia. What does this condition involve?", options: ["Loss of vision", "Lack of awareness or denial of one's own neurological deficits — the client genuinely does not recognize that they have impairments such as hemiplegia or neglect", "Language difficulties", "Memory loss only"], correctIndex: 1, rationale: "Anosognosia: unawareness of own deficits (not denial — genuinely does not perceive the impairment). Common after right hemisphere stroke. Affects safety, therapy participation, and discharge planning. Use experiential feedback to gradually build awareness.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2489", stem: "An OTA is treating a client in home health who lives alone and has a history of falls. What is the MOST critical recommendation?", options: ["Only exercise program", "Personal emergency response system (PERS/medical alert) — ensures the client can summon help if they fall and cannot get up, which is essential for safety living alone", "Only grab bars", "Only medication review"], correctIndex: 1, rationale: "Falls alone at home: personal emergency response system is critical (pendant/wristband alert device). Additional: home hazard modification, exercise program, medication review, vision check, and establishing a buddy system for daily check-ins.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2490", stem: "A client with a replanted hand is 3 months post-surgery. What functional goal is realistic?", options: ["Normal hand function", "Protective sensation, gross grasp sufficient for functional activities, and modified independence in ADLs — full normal function is rarely achieved after hand replantation", "No function return expected", "Only cosmetic result"], correctIndex: 1, rationale: "Hand replantation 3-month expectations: progressing protective sensation, developing grasp/pinch (may be limited), modified independence in ADLs, and ongoing sensory re-education. Full normal function rarely achieved but useful functional hand possible.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2491", stem: "An OTA is treating a client with attention deficit hyperactivity disorder (adult ADHD). Which environmental modification improves task completion?", options: ["More distractions to build tolerance", "Minimize environmental distractions, organize workspace, use timers for task segments, provide visual schedules, and establish consistent routines", "No modifications help for adults", "Only medication"], correctIndex: 1, rationale: "Adult ADHD environmental modifications: minimize distractions (quiet workspace, noise-canceling headphones), organized workspace, timers for task segments, visual schedules/checklists, consistent routines, and break tasks into smaller chunks.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Cognitive Rehab" },
  { id: "ota-2492", stem: "A client with a transhumeral amputation is being fitted with a hybrid prosthesis. What does hybrid mean in this context?", options: ["Two prostheses", "A prosthesis that combines body-powered components (typically for the elbow) with myoelectric components (typically for the hand/terminal device)", "Only cosmetic", "Battery-powered throughout"], correctIndex: 1, rationale: "Hybrid prosthesis: combines body-powered (cable-operated elbow — direct feedback, reliable) with myoelectric (powered hand/TD — better cosmesis, stronger grip). Advantages: leverages strengths of both systems for optimal function.", difficulty: 3, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2493", stem: "An OTA is treating a client with progressive multiple sclerosis who is experiencing cognitive decline. What compensatory strategy is MOST helpful?", options: ["Memory drills", "External memory aids such as smartphone reminders, written lists, organized environment, consistent routines, and calendars for managing daily tasks", "Brain training games only", "No strategies help with MS cognition"], correctIndex: 1, rationale: "MS cognitive decline: external memory aids (smartphone, lists, calendars), consistent routines, organized environment, one task at a time, rest before cognitive tasks, and structured daily schedule. External aids more effective than memory drills.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2494", stem: "A client with a PIP joint replacement (arthroplasty) has which postoperative motion restriction?", options: ["No restrictions", "Avoid lateral stress to the PIP joint — follow surgeon-specific ROM and resistance progression while protecting the implant from excessive forces", "Full activity immediately", "Permanent immobilization"], correctIndex: 1, rationale: "PIP arthroplasty: avoid lateral stress (protect implant), follow specific ROM protocol (usually dynamic extension splinting), gentle AROM, and progressive functional use. Long-term: avoid heavy grip force and lateral stress to the joint.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2495", stem: "An OTA is providing intervention for a child with nonverbal learning disability (NVLD). Which deficit is MOST characteristic?", options: ["Verbal skill deficits", "Visual-spatial processing deficits, poor motor coordination, difficulty with novel situations, and social perception problems — despite strong verbal and reading skills", "Reading disability", "Hearing impairment"], correctIndex: 1, rationale: "NVLD profile: strong verbal/reading skills but impaired visual-spatial processing, motor coordination deficits, difficulty with novel situations, poor social perception (misread nonverbal cues), and math difficulties. OT addresses motor and social-perceptual deficits.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2496", stem: "A client with a biceps tendon rupture at the shoulder (long head) has which functional limitation?", options: ["Loss of shoulder flexion", "Mild weakness in elbow supination and flexion (Popeye deformity), but most clients maintain functional strength due to intact short head and brachialis", "Complete loss of elbow flexion", "Loss of wrist extension"], correctIndex: 1, rationale: "Long head biceps rupture: Popeye deformity (muscle belly retracts), mild weakness in supination/flexion. Most clients maintain functional strength (short head and brachialis intact). Surgical repair considered for young, active patients.", difficulty: 3, category: "Anatomy & Physiology", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2497", stem: "An OTA is teaching a client with low vision to organize medications. What adaptation ensures safety?", options: ["Keep all medications in one bottle", "Use a weekly pill organizer with large compartments, high-contrast labels, magnification for reading labels, and a medication schedule in large print", "Only liquid medications", "Rely entirely on memory"], correctIndex: 1, rationale: "Low vision medication safety: weekly pill organizer (pre-filled by pharmacist/caregiver), high-contrast labels, large-print medication list, magnification devices, talking prescription labels, and organized medication station with task lighting.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2498", stem: "A client with moderate intellectual disability is participating in a supported employment program. What level of job coaching is typically needed?", options: ["No job coaching", "Ongoing on-site job coaching that fades to periodic check-ins as the client develops competence in specific job tasks and routines", "Full-time permanent job coach", "Only initial orientation"], correctIndex: 1, rationale: "Supported employment for moderate ID: initial intensive on-site job coaching, systematic task training, gradual fading of support as competence develops, periodic check-ins, and crisis support as needed. Goal is maximum independence with minimum support.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2499", stem: "An OTA is treating a client with a healing fifth metacarpal fracture. When can the client return to full grip activities?", options: ["At 2 weeks", "Typically at 6-8 weeks when radiographic healing is confirmed — progressive grip strengthening can begin with full activity return at 8-12 weeks", "Immediately", "At 6 months"], correctIndex: 1, rationale: "Fifth MC fracture: radiographic healing typically 6-8 weeks. Progressive grip strengthening at 6-8 weeks, gradual return to full activities. Full return to contact sports/heavy grip at 8-12 weeks per physician clearance.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2500", stem: "A client with bilateral lower extremity amputations is transitioning from hospital to community. What is the OTA's primary role?", options: ["Only prosthetic training", "Comprehensive ADL training, home modification recommendations, wheelchair skills for community mobility, adaptive equipment for independence, and psychosocial support for community reintegration", "Only discharge planning", "Only caregiver training"], correctIndex: 1, rationale: "Bilateral LE amputation community transition: ADL training (bathing, dressing, transfers from wheelchair), home modification recommendations, wheelchair skills for community mobility, adaptive equipment, psychosocial support, and community reintegration planning.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2501", stem: "An OTA is treating a client with an acute exacerbation of rheumatoid arthritis. Which intervention is appropriate during a flare?", options: ["Aggressive strengthening", "Resting hand splints for joint protection, gentle AROM within pain limits, energy conservation, and activity modification to reduce joint stress during the inflammatory episode", "Maximum resistance exercises", "No intervention during flare"], correctIndex: 1, rationale: "RA acute flare: rest inflamed joints (resting splints), gentle AROM only (within pain limits), energy conservation, activity modification, ice for inflamed joints, and joint protection principles. Avoid resistive exercise during active inflammation.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2502", stem: "A client with a spinal cord injury is being taught skin inspection. Why is this education critical?", options: ["Cosmetic purposes", "Loss of sensation below the injury level means the client cannot feel pressure, friction, or temperature damage — skin inspection prevents pressure injuries that could become life-threatening", "Only for cleanliness", "Not important for SCI"], correctIndex: 1, rationale: "SCI skin inspection: loss of sensation means no warning of tissue damage. Inspect all weight-bearing surfaces twice daily (use mirror for posterior areas). Look for redness, blanching, blisters, and warmth. Early detection prevents serious pressure injuries.", difficulty: 1, category: "Patient Education", topic: "Neurological Rehab" },
];
